using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Register the training service and train on startup
builder.Services.AddSingleton<ModelTrainingService>();

var app = builder.Build();

// Train the model at startup and log evaluation metrics
var trainer = app.Services.GetRequiredService<ModelTrainingService>();
trainer.TrainAndEvaluate();

// Register PredictionEnginePool from the trained model file
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath);

// Rebuild the service provider to include the pool (needed since we added after initial build)
// Instead, restructure: register pool before building
// Let's restructure properly:

// This pattern requires knowing the model path before build, so we do a two-phase approach:
app.MapControllers();
app.Run();

